<?php
require_once __DIR__.'/functions.php';
$posts=db()->query("SELECT p.id,p.titulo,p.slug,p.contenido,p.imagen,p.author_name,p.fecha,m.avatar FROM posts p LEFT JOIN members m ON m.id=p.member_author_id WHERE p.post_type='community' AND p.status='published' ORDER BY p.fecha DESC")->fetchAll();
render_header('Comunidad',['canonical'=>'/community.php']);?><header class="hero"><h1>Comunidad</h1><p>Publicaciones creadas por los lectores.</p><?php if(is_member_verified()):?><a class="button" href="/community-write.php">Crear publicación</a><?php endif;?></header><div class="grid"><?php foreach($posts as $post):?><article class="card"><?php if($post['imagen']):?><img src="/uploads/<?=e($post['imagen'])?>" alt="<?=e($post['titulo'])?>"><?php endif;?><div class="pad"><div class="author-meta"><?php if($post['avatar']):?><img class="avatar avatar-sm" src="/uploads/<?=e($post['avatar'])?>" alt=""><?php endif;?><small><?=e(format_date($post['fecha']))?> · <?=e($post['author_name'])?></small></div><h2><a href="<?=e(post_url($post))?>"><?=e($post['titulo'])?></a></h2><p><?=e(mb_strimwidth(strip_tags($post['contenido']),0,150,'…'))?></p><a class="more" href="<?=e(post_url($post))?>">Abrir conversación →</a></div></article><?php endforeach;?><?php if(!$posts):?><p class="empty">Todavía no hay publicaciones de la comunidad.</p><?php endif;?></div><?php render_footer();
